head.b:skin:
/* ══════════════════════════════════════════════════════
   The 4th Path — CNN Multi-Section Layout
   Independent Tech Media by 22B Labs
   ══════════════════════════════════════════════════════ */

@import url('https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=DM+Sans:ital,wght@0,400;0,500;0,600;0,700;1,400&family=IBM+Plex+Mono:wght@400;500&family=Noto+Sans+KR:wght@300;400;500;600;700;900&display=swap');

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Noto Sans KR', 'DM Sans', -apple-system, sans-serif;
  background: #f0efeb;
  color: #111;
  line-height: 1.6;
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
}
a { color: #111; text-decoration: none; transition: all 0.15s; }
a:hover { color: #b8941e; }
img { max-width: 100%; height: auto; }

/* ══ TOP STRIP ══ */
.ts { background: #000; font-size: 11px; color: #888; }
.ts-i { max-width: 1320px; margin: 0 auto; padding: 7px 20px; display: flex; justify-content: space-between; align-items: center; }
.ts-l { display: flex; align-items: center; gap: 12px; }
.dot-live { width: 7px; height: 7px; background: #c8a84e; border-radius: 50%; animation: p 2s infinite; }
@keyframes p { 0%,100%{opacity:1}50%{opacity:.3} }
.ts a { color: #777; margin-left: 16px; }
.ts a:hover { color: #c8a84e; }

/* ══ MASTHEAD ══ */
.mh { background: #fff; text-align: center; padding: 20px 20px 16px; border-bottom: 3px solid #000; }
.mh-logo { font-family: 'Instrument Serif', Georgia, serif; font-size: 3.2em; font-weight: 400; color: #000; letter-spacing: -1px; }
.mh-logo em { font-style: italic; color: #b8941e; }
.mh-tag { font-family: 'DM Sans', sans-serif; font-size: 10px; color: #999; letter-spacing: 3.5px; text-transform: uppercase; margin-top: 5px; }

/* ══ NAV ══ */
.nav { background: #fff; border-bottom: 1px solid #e0e0e0; position: sticky; top: 0; z-index: 1000; box-shadow: 0 1px 3px rgba(0,0,0,.04); }
.nav-i { max-width: 1320px; margin: 0 auto; display: flex; align-items: center; justify-content: center; flex-wrap: wrap; }
.pages-widget ul, .PageList ul { list-style: none; display: flex; justify-content: center; flex-wrap: wrap; margin: 0; padding: 0; }
.nav a, .pages-widget a, .PageList a {
  display: inline-block; color: #333; font-family: 'DM Sans'; font-size: 12px; font-weight: 600;
  letter-spacing: 1.2px; text-transform: uppercase; padding: 13px 18px;
  border-bottom: 2px solid transparent;
}
.nav a:hover, .pages-widget a:hover { color: #000; border-bottom-color: #c8a84e; }

/* ══ HOMEPAGE SECTIONS ══ */
.hp { max-width: 1320px; margin: 0 auto; padding: 0 20px; }

/* ── Hero Section (최신 1개 대형) ── */
.hero { padding: 28px 0; border-bottom: 2px solid #000; }
.hero-grid { display: grid; grid-template-columns: 1.6fr 1fr; gap: 28px; }
.hero-main {}
.hero-cat { font-family: 'DM Sans'; font-size: 10px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: #c8a84e; margin-bottom: 8px; }
.hero-title { font-family: 'Noto Sans KR'; font-size: 2em; font-weight: 900; color: #000; line-height: 1.22; margin-bottom: 10px; letter-spacing: -0.5px; }
.hero-title a { color: #000; }
.hero-title a:hover { color: #b8941e; }
.hero-meta { font-size: 11.5px; color: #999; margin-bottom: 10px; font-family: 'DM Sans'; }
.hero-desc { font-size: 15px; color: #444; line-height: 1.7; }
.hero-side { border-left: 1px solid #e0e0e0; padding-left: 24px; }
.hero-side-item { padding: 14px 0; border-bottom: 1px solid #eee; }
.hero-side-item:last-child { border-bottom: none; }
.hero-side-cat { font-family: 'DM Sans'; font-size: 9px; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; color: #c8a84e; margin-bottom: 4px; }
.hero-side-title { font-size: 14px; font-weight: 700; color: #111; line-height: 1.35; }
.hero-side-title a { color: #111; }
.hero-side-title a:hover { color: #b8941e; }
.hero-side-meta { font-size: 10.5px; color: #aaa; margin-top: 3px; font-family: 'DM Sans'; }

/* ── Section Headers ── */
.sec-head { display: flex; align-items: center; gap: 12px; padding: 20px 0 14px; border-bottom: 2px solid #000; margin-bottom: 20px; }
.sec-dot { width: 10px; height: 10px; border-radius: 50%; flex-shrink: 0; }
.sec-title { font-family: 'DM Sans'; font-size: 13px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: #000; }
.sec-en { font-size: 11px; color: #bbb; letter-spacing: 1px; margin-left: 8px; }
.sec-more { margin-left: auto; font-family: 'DM Sans'; font-size: 10px; font-weight: 600; color: #c8a84e; letter-spacing: 1px; text-transform: uppercase; }
.sec-more:hover { color: #8b6914; }

/* ── Card Grid (코너별 글 목록) ── */
.card-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; margin-bottom: 36px; }
.card { background: #fff; border: 1px solid #e8e8e4; transition: box-shadow 0.2s; }
.card:hover { box-shadow: 0 4px 16px rgba(0,0,0,.06); }
.card-body { padding: 18px 20px 20px; }
.card-cat { font-family: 'DM Sans'; font-size: 9px; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; color: #c8a84e; margin-bottom: 6px; }
.card-title { font-size: 15px; font-weight: 700; color: #000; line-height: 1.35; margin-bottom: 6px; }
.card-title a { color: #000; }
.card-title a:hover { color: #b8941e; }
.card-meta { font-size: 10.5px; color: #aaa; font-family: 'DM Sans'; }
.card-desc { font-size: 13px; color: #666; line-height: 1.6; margin-top: 8px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }

/* ── Two Column Section ── */
.two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-bottom: 36px; }
.list-item { padding: 14px 0; border-bottom: 1px solid #eee; display: flex; gap: 12px; }
.list-item:last-child { border-bottom: none; }
.list-num { font-family: 'Instrument Serif', serif; font-size: 2em; color: #e0e0da; font-weight: 400; line-height: 1; min-width: 32px; }
.list-content {}
.list-title { font-size: 14px; font-weight: 700; color: #111; line-height: 1.35; }
.list-title a { color: #111; }
.list-title a:hover { color: #b8941e; }
.list-meta { font-size: 10px; color: #aaa; margin-top: 3px; font-family: 'DM Sans'; }

/* ── Full Width Banner Section ── */
.banner-sec { background: #0c0c10; padding: 28px 0; margin: 0 -20px 36px; }
.banner-inner { max-width: 1320px; margin: 0 auto; padding: 0 20px; display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 24px; }
.banner-card {}
.banner-cat { font-family: 'DM Sans'; font-size: 9px; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; color: #c8a84e; margin-bottom: 6px; }
.banner-title { font-size: 15px; font-weight: 700; color: #fff; line-height: 1.35; margin-bottom: 4px; }
.banner-title a { color: #fff; }
.banner-title a:hover { color: #c8a84e; }
.banner-meta { font-size: 10px; color: #666; font-family: 'DM Sans'; }

/* ══ INDIVIDUAL POST PAGE (글 상세보기) ══ */
.post-body, .entry-content {
  font-family: 'Noto Sans KR', 'DM Sans', Georgia, sans-serif;
  font-size: 17px; line-height: 1.9; color: #222; max-width: 720px;
}
.post-body h1 { font-size: 1.7em; font-weight: 800; color: #000; margin: 48px 0 14px; padding-bottom: 10px; border-bottom: 2px solid #c8a84e; }
.post-body h2 { font-size: 1.3em; font-weight: 700; color: #111; margin: 40px 0 10px; padding-left: 14px; border-left: 3px solid #c8a84e; }
.post-body h3 { font-size: 1.1em; font-weight: 700; color: #222; margin: 32px 0 6px; }
.post-body p { margin-bottom: 22px; }
.post-body code { font-family: 'IBM Plex Mono', monospace; background: #f4f4f0; padding: 2px 6px; border-radius: 2px; font-size: .87em; color: #8b4513; }
.post-body pre { background: #0c0c10; color: #d4d4cc; padding: 20px 24px; overflow-x: auto; font-family: 'IBM Plex Mono'; font-size: .84em; line-height: 1.65; border-left: 3px solid #c8a84e; margin: 28px 0; }
.post-body pre code { background: transparent; color: inherit; padding: 0; }
.post-body table { width: 100%; border-collapse: collapse; margin: 28px 0; font-size: 13.5px; }
.post-body th { background: #0c0c10; color: #fff; padding: 11px 14px; text-align: left; font-weight: 600; font-size: 11px; letter-spacing: .8px; text-transform: uppercase; }
.post-body td { padding: 10px 14px; border-bottom: 1px solid #eee; }
.post-body tr:hover td { background: #f5f5f0; }
.post-body blockquote { border-left: 3px solid #c8a84e; padding: 4px 0 4px 24px; margin: 28px 0; font-family: 'Instrument Serif', serif; font-size: 1.15em; font-style: italic; color: #444; }
.post-body a { color: #8b6914; text-decoration: underline; text-underline-offset: 3px; }
.post-body a:hover { color: #b8941e; }
.post-body hr { border: none; border-top: 1px solid #ddd; margin: 44px 0; }
.post-body ul, .post-body ol { padding-left: 24px; margin-bottom: 20px; }
.post-body li { margin-bottom: 6px; }

.post-labels { margin-top: 12px; }
.post-labels a { font-size: 10px; color: #888; letter-spacing: .5px; padding: 3px 8px; border: 1px solid #e8e8e5; margin-right: 4px; display: inline-block; }
.post-labels a:hover { border-color: #c8a84e; color: #c8a84e; }

/* ══ PAGINATION ══ */
.blog-pager { text-align: center; padding: 32px 0; }
.blog-pager a { display: inline-block; padding: 10px 28px; font-size: 11px; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; color: #000; border: 1px solid #000; margin: 0 8px; }
.blog-pager a:hover { background: #000; color: #fff; }

/* ══ FOOTER ══ */
.ft { background: #0c0c10; color: #777; margin-top: 48px; }
.ft-i { max-width: 1320px; margin: 0 auto; padding: 44px 20px 24px; }
.ft-grid { display: grid; grid-template-columns: 2fr 1fr 1fr; gap: 40px; padding-bottom: 28px; border-bottom: 1px solid #1a1a20; }
.ft-col-t { font-family: 'DM Sans'; font-size: 10px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: #c8a84e; margin-bottom: 12px; }
.ft-col p { font-size: 13px; color: #666; line-height: 1.7; }
.ft-col ul { list-style: none; }
.ft-col li { padding: 3px 0; }
.ft-col a { color: #888; font-size: 13px; }
.ft-col a:hover { color: #c8a84e; }
.ft-brand { font-family: 'Instrument Serif', serif; font-size: 1.5em; color: #fff; margin-bottom: 8px; }
.ft-brand em { color: #c8a84e; }
.ft-btm { padding-top: 16px; text-align: center; font-size: 10.5px; color: #444; letter-spacing: .8px; }
.ft-btm a { color: #c8a84e; }

/* ══ 한 컷 (One Cut) Cartoon Section ══ */
.onecut-sec {
  border-top: 2px solid #000;
  border-bottom: 2px solid #000;
  padding: 24px 0;
  margin: 28px 0;
  background: #faf9f6;
}
.onecut-head {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 18px;
}
.onecut-badge {
  background: #c8a84e;
  color: #fff;
  font-family: 'DM Sans', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  padding: 4px 12px;
}
.onecut-label {
  font-family: 'DM Sans', sans-serif;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: #000;
}
.onecut-sublabel {
  font-size: 11px;
  color: #bbb;
  letter-spacing: 1px;
  margin-left: 6px;
}
.onecut-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}
.onecut-card {
  display: flex;
  gap: 20px;
  background: #fff;
  border: 1px solid #e8e8e4;
  padding: 0;
  overflow: hidden;
  transition: box-shadow 0.2s;
}
.onecut-card:hover {
  box-shadow: 0 4px 16px rgba(0,0,0,0.08);
}
.onecut-img {
  width: 200px;
  min-height: 150px;
  background: #e8e8e4;
  flex-shrink: 0;
  object-fit: cover;
}
.onecut-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.onecut-content {
  padding: 18px 20px 18px 0;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.onecut-title {
  font-family: 'Noto Sans KR', sans-serif;
  font-size: 15px;
  font-weight: 700;
  color: #000;
  line-height: 1.4;
  margin-bottom: 6px;
}
.onecut-title a { color: #000; }
.onecut-title a:hover { color: #b8941e; }
.onecut-meta {
  font-family: 'DM Sans', sans-serif;
  font-size: 10.5px;
  color: #aaa;
}
.onecut-desc {
  font-size: 13px;
  color: #666;
  line-height: 1.5;
  margin-top: 6px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
/* 한 컷이 1개만 있을 때 전체 너비 사용 */
.onecut-single {
  grid-template-columns: 1fr;
}
.onecut-single .onecut-card {
  max-width: 100%;
}
.onecut-single .onecut-img {
  width: 320px;
  min-height: 200px;
}
.onecut-single .onecut-title {
  font-size: 18px;
}

@media (max-width:768px) {
  .onecut-grid { grid-template-columns: 1fr; }
  .onecut-card { flex-direction: column; }
  .onecut-img { width: 100%; min-height: 180px; }
  .onecut-content { padding: 16px; }
  .onecut-single .onecut-img { width: 100%; }
}

/* ══ Ad Slots ══ */
.ad-slot {
  background: #f7f7f5;
  border: 1px dashed #ddd;
  text-align: center;
  padding: 20px;
  margin: 28px 0;
  font-family: 'DM Sans', sans-serif;
  font-size: 11px;
  color: #bbb;
  letter-spacing: 1px;
  text-transform: uppercase;
  min-height: 90px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.ad-slot-dark {
  background: #13131a;
  border-color: #2a2a30;
  color: #444;
}
/* AdSense 승인 후: .ad-slot의 border/background/text를 제거하고 AdSense 코드를 안에 넣으면 됩니다 */

/* ══ Loading skeleton ══ */
.skel { background: linear-gradient(90deg, #f0f0ec 25%, #e8e8e4 50%, #f0f0ec 75%); background-size: 200% 100%; animation: shimmer 1.5s infinite; border-radius: 3px; }
@keyframes shimmer { 0%{background-position:200% 0}100%{background-position:-200% 0} }
.skel-title { height: 16px; width: 80%; margin-bottom: 8px; }
.skel-meta { height: 10px; width: 40%; }

/* ══ Post Page — Two Column Layout ══ */
.post-page-grid {
  display: grid;
  grid-template-columns: 1fr 300px;
  gap: 36px;
  max-width: 1200px;
  margin: 0 auto;
  padding: 24px 20px 0;
}
.post-main { min-width: 0; }
.post-sidebar {
  border-left: 1px solid #e8e8e5;
  padding-left: 24px;
}
.ps-section {
  margin-bottom: 28px;
  padding-bottom: 20px;
  border-bottom: 1px solid #eee;
}
.ps-section:last-child { border-bottom: none; }
.ps-title {
  font-family: 'DM Sans', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 2.5px;
  text-transform: uppercase;
  color: #000;
  margin-bottom: 14px;
  padding-bottom: 8px;
  border-bottom: 2px solid #c8a84e;
}
.ps-nav-item {
  display: block;
  padding: 10px 0;
  border-bottom: 1px solid #f0f0ec;
}
.ps-nav-item:last-child { border-bottom: none; }
.ps-nav-label {
  font-family: 'DM Sans', sans-serif;
  font-size: 9px;
  font-weight: 600;
  color: #c8a84e;
  letter-spacing: 1px;
  text-transform: uppercase;
}
.ps-nav-title {
  font-size: 13.5px;
  font-weight: 600;
  color: #222;
  line-height: 1.4;
  margin-top: 2px;
}
.ps-nav-title:hover { color: #b8941e; }
.ps-nav-date {
  font-family: 'DM Sans', sans-serif;
  font-size: 10px;
  color: #bbb;
  margin-top: 2px;
}
.ps-prevnext a {
  display: block;
  padding: 10px 0;
  font-size: 13px;
  font-weight: 600;
  color: #333;
  border-bottom: 1px solid #f0f0ec;
}
.ps-prevnext a:hover { color: #b8941e; }
.ps-prevnext .dir {
  font-family: 'DM Sans', sans-serif;
  font-size: 9px;
  color: #999;
  letter-spacing: 1px;
  text-transform: uppercase;
}
.ps-corners { list-style: none; padding: 0; margin: 0; }
.ps-corners li { padding: 7px 0; border-bottom: 1px solid #f0f0ec; }
.ps-corners li:last-child { border-bottom: none; }
.ps-corners a { font-size: 13px; color: #333; font-weight: 500; }
.ps-corners a:hover { color: #b8941e; }
.ps-corner-dot { display: inline-block; width: 7px; height: 7px; border-radius: 50%; margin-right: 8px; }

/* ══ Search Bar ══ */
.nav-search {
  display: flex;
  align-items: center;
  margin-left: auto;
  padding: 0 4px;
}
.nav-search-input {
  font-family: 'Noto Sans KR', 'DM Sans', sans-serif;
  font-size: 12px;
  padding: 6px 12px;
  border: 1px solid #e0e0e0;
  border-radius: 2px;
  background: #fafaf8;
  color: #333;
  width: 0;
  opacity: 0;
  transition: width 0.3s, opacity 0.3s, padding 0.3s;
  outline: none;
}
.nav-search-input.open {
  width: 180px;
  opacity: 1;
  padding: 6px 12px;
}
.nav-search-input:focus { border-color: #c8a84e; }
.nav-search-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 14px;
  color: #888;
  padding: 13px 10px;
  transition: color 0.15s;
}
.nav-search-btn:hover { color: #c8a84e; }

/* ══ All Posts Page ══ */
.allposts-page {
  max-width: 1320px;
  margin: 0 auto;
  padding: 28px 20px;
}
.allposts-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-bottom: 16px;
  border-bottom: 2px solid #000;
  margin-bottom: 24px;
}
.allposts-title {
  font-family: 'DM Sans', sans-serif;
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
}
.allposts-count {
  font-family: 'DM Sans', sans-serif;
  font-size: 11px;
  color: #999;
}
.allposts-filters {
  display: flex;
  gap: 8px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}
.allposts-filter {
  font-family: 'DM Sans', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1px;
  text-transform: uppercase;
  padding: 6px 14px;
  border: 1px solid #e0e0e0;
  background: #fff;
  color: #666;
  cursor: pointer;
  transition: all 0.15s;
}
.allposts-filter:hover, .allposts-filter.active {
  border-color: #c8a84e;
  color: #c8a84e;
  background: #faf8f0;
}
.allposts-list { list-style: none; margin: 0; padding: 0; }
.allposts-item {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  padding: 12px 0;
  border-bottom: 1px solid #f0f0ec;
  gap: 16px;
}
.allposts-item:hover { background: #faf9f6; }
.allposts-item-left { flex: 1; min-width: 0; }
.allposts-item-label {
  font-family: 'DM Sans', sans-serif;
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: #c8a84e;
}
.allposts-item-title {
  font-size: 15px;
  font-weight: 600;
  color: #111;
  line-height: 1.4;
  margin-top: 2px;
}
.allposts-item-title a { color: #111; }
.allposts-item-title a:hover { color: #b8941e; }
.allposts-item-date {
  font-family: 'DM Sans', sans-serif;
  font-size: 11px;
  color: #bbb;
  white-space: nowrap;
  flex-shrink: 0;
}

/* ══ RESPONSIVE ══ */
@media (max-width:1024px) {
  .hero-grid { grid-template-columns: 1fr; }
  .hero-side { border-left: none; padding-left: 0; border-top: 1px solid #eee; padding-top: 16px; }
  .card-grid { grid-template-columns: repeat(2, 1fr); }
  .banner-inner { grid-template-columns: 1fr; }
  .two-col { grid-template-columns: 1fr; }
  .ft-grid { grid-template-columns: 1fr; }
  .post-page-grid { grid-template-columns: 1fr; }
  .post-sidebar { border-left: none; padding-left: 0; border-top: 1px solid #e8e8e5; padding-top: 24px; }
}
@media (max-width:640px) {
  .card-grid { grid-template-columns: 1fr; }
  .mh-logo { font-size: 2.2em; }
  .hero-title { font-size: 1.5em; }
  .nav a { padding: 11px 10px; font-size: 10px; }
  .nav-search-input.open { width: 120px; }
  .ts .ts-right { display: none; }
  .allposts-item { flex-direction: column; gap: 4px; }
  .allposts-filters { gap: 4px; }
  .allposts-filter { font-size: 10px; padding: 4px 10px; }
}

.header-widget { display: none; }
.feed-links, .blog-feeds, .post-share-buttons { display: none; }

