b:if.script:
//
(function(){
  var blogUrl = "https://www.the4thpath.com";
  var corners = [
    {label:"", color:"#c8a84e", ko:"최신", en:"Latest"},
  ];

  // 전체 글 가져오기
  function fetchPosts(callback) {
    var script = document.createElement('script');
    script.src = blogUrl + '/feeds/posts/default?alt=json-in-script&max-results=20&callback=' + callback;
    document.body.appendChild(script);
  }

  window.renderHomepage = function(data) {
    var entries = data.feed.entry || [];
    if(entries.length === 0) return;

    var posts = entries.map(function(e){
      var link = "";
      for(var i=0;i<e.link.length;i++){
        if(e.link[i].rel==="alternate"){link=e.link[i].href;break;}
      }
      var labels = [];
      if(e.category){
        for(var j=0;j<e.category.length;j++){
          labels.push(e.category[j].term);
        }
      }
      var snippet = "";
      if(e.content) {
        var tmp = document.createElement("div");
        tmp.innerHTML = e.content.$t || "";
        // Remove style, script, and noscript tags entirely
        var badTags = tmp.querySelectorAll("style, script, noscript");
        for(var k=0;k<badTags.length;k++) badTags[k].remove();
        var rawText = tmp.textContent || tmp.innerText || "";
        // Remove leftover CSS-like patterns
        rawText = rawText.replace(/\.[a-zA-Z-]+[\s]*\{[^}]*\}/g, "");
        rawText = rawText.replace(/@[a-zA-Z]+[^;{]*[{;][^}]*/g, "");
        rawText = rawText.replace(/\s{2,}/g, " ").trim();
        snippet = rawText.substring(0,220) + "...";
      }
      if(!snippet && e.summary) {
        snippet = (e.summary.$t || "").replace(/<[^>]*>/g,"").substring(0,220) + "...";
      }
      var date = "";
      if(e.published) {
        var d = new Date(e.published.$t);
        date = d.getFullYear() + "." + ("0"+(d.getMonth()+1)).slice(-2) + "." + ("0"+d.getDate()).slice(-2);
      }
      return {
        title: e.title.$t,
        url: link,
        labels: labels,
        snippet: snippet,
        date: date
      };
    });

    // 한컷 라벨 글은 메인 피드에서 제외 (전용 섹션에서 별도 표시)
    posts = posts.filter(function(p){
      return p.labels.indexOf("한컷") === -1;
    });

    // Helper: label에서 첫 번째 가져오기
    function getLabel(p){ return p.labels.length > 0 ? p.labels[0] : ""; }

    // Helper: HTML 생성
    function heroMainHTML(p){
      return '<div class="hero-cat">' + getLabel(p) + '</div>' +
        '<h2 class="hero-title"><a href="' + p.url + '">' + p.title + '</a></h2>' +
        '<div class="hero-meta">' + p.date + ' · 22B Labs</div>' +
        '<div class="hero-desc">' + p.snippet.substring(0,250) + '</div>';
    }

    function heroSideHTML(p){
      return '<div class="hero-side-item">' +
        '<div class="hero-side-cat">' + getLabel(p) + '</div>' +
        '<div class="hero-side-title"><a href="' + p.url + '">' + p.title + '</a></div>' +
        '<div class="hero-side-meta">' + p.date + '</div></div>';
    }

    function cardHTML(p){
      return '<div class="card"><div class="card-body">' +
        '<div class="card-cat">' + getLabel(p) + '</div>' +
        '<div class="card-title"><a href="' + p.url + '">' + p.title + '</a></div>' +
        '<div class="card-meta">' + p.date + '</div>' +
        '<div class="card-desc">' + p.snippet.substring(0,120) + '</div>' +
        '</div></div>';
    }

    function listItemHTML(p, num){
      return '<div class="list-item">' +
        '<div class="list-num">' + num + '</div>' +
        '<div class="list-content">' +
        '<div class="list-title"><a href="' + p.url + '">' + p.title + '</a></div>' +
        '<div class="list-meta">' + p.date + ' · ' + getLabel(p) + '</div>' +
        '</div></div>';
    }

    function bannerCardHTML(p){
      return '<div class="banner-card">' +
        '<div class="banner-cat">' + getLabel(p) + '</div>' +
        '<div class="banner-title"><a href="' + p.url + '">' + p.title + '</a></div>' +
        '<div class="banner-meta">' + p.date + '</div></div>';
    }

    function secHeadHTML(ko, en, color, labelUrl){
      var more = labelUrl ? '<a class="sec-more" href="' + labelUrl + '">More →</a>' : '';
      return '<div class="sec-head">' +
        '<span class="sec-dot" style="background:' + color + '"></span>' +
        '<span class="sec-title">' + ko + '</span>' +
        '<span class="sec-en">' + en + '</span>' +
        more + '</div>';
    }

    // ── Hero: 첫 1개 + 사이드 4개 ──
    var heroEl = document.getElementById("hero-main");
    var sideEl = document.getElementById("hero-side");
    if(posts.length > 0) heroEl.innerHTML = heroMainHTML(posts[0]);
    var sideHTML = "";
    for(var s=1; s<Math.min(5, posts.length); s++){
      sideHTML += heroSideHTML(posts[s]);
    }
    sideEl.innerHTML = sideHTML;

    // ── Section 1: 6~8번째 글 3개 카드 ──
    var sec1 = document.getElementById("sec-grid-1");
    var sec1HTML = secHeadHTML("최신 기사", "Latest Articles", "#c8a84e", "");
    sec1HTML += '<div class="card-grid">';
    for(var c=5; c<Math.min(8, posts.length); c++){
      sec1HTML += cardHTML(posts[c]);
    }
    sec1HTML += '</div>';
    sec1.innerHTML = sec1HTML;

    // ── Dark Banner: 9~11번째 글 ──
    var banner = document.getElementById("dark-banner");
    if(posts.length > 10){
      var bHTML = '<div class="banner-sec"><div class="banner-inner">';
      for(var b=8; b<Math.min(11, posts.length); b++){
        bHTML += bannerCardHTML(posts[b]);
      }
      bHTML += '</div></div>';
      banner.innerHTML = bHTML;
    }

    // ── Two Column: 12~19번째 글 번호 리스트 ──
    var twocol = document.getElementById("sec-twocol");
    if(posts.length > 11){
      var tHTML = secHeadHTML("더 많은 기사", "More Stories", "#333", "");
      tHTML += '<div class="two-col"><div>';
      var half = Math.min(15, posts.length);
      var mid = 11 + Math.ceil((half - 11) / 2);
      for(var t=11; t<mid; t++){
        tHTML += listItemHTML(posts[t], t-10);
      }
      tHTML += '</div><div>';
      for(var t2=mid; t2<half; t2++){
        tHTML += listItemHTML(posts[t2], t2-10);
      }
      tHTML += '</div></div>';
      twocol.innerHTML = tHTML;
    }

    // ── Section 2: 나머지 3개 카드 ──
    var sec2 = document.getElementById("sec-grid-2");
    if(posts.length > 15){
      var s2HTML = secHeadHTML("아카이브", "Archive", "#888", "");
      s2HTML += '<div class="card-grid">';
      for(var a=15; a<Math.min(18, posts.length); a++){
        s2HTML += cardHTML(posts[a]);
      }
      s2HTML += '</div>';
      sec2.innerHTML = s2HTML;
    }
  };

  fetchPosts("renderHomepage");

  // ── 한 컷 (One Cut) 전용 섹션 ──
  // "한컷" 라벨이 달린 글만 별도로 가져와서 이미지와 함께 표시
  window.renderOnecut = function(data) {
    var entries = data.feed.entry || [];
    if(entries.length === 0) return;

    var section = document.getElementById("onecut-section");
    var grid = document.getElementById("onecut-grid");
    var html = "";
    var count = Math.min(entries.length, 4);

    if(count === 1) grid.className = "onecut-grid onecut-single";

    for(var i=0; i<count; i++){
      var e = entries[i];
      var link = "";
      for(var j=0;j<e.link.length;j++){
        if(e.link[j].rel==="alternate"){link=e.link[j].href;break;}
      }
      var title = e.title.$t || "";
      var date = "";
      if(e.published){
        var d = new Date(e.published.$t);
        date = d.getFullYear()+"."+ ("0"+(d.getMonth()+1)).slice(-2)+"."+ ("0"+d.getDate()).slice(-2);
      }

      // 글 본문에서 첫 번째 이미지 추출
      var imgUrl = "";
      if(e.content && e.content.$t){
        var tmpDiv = document.createElement("div");
        tmpDiv.innerHTML = e.content.$t;
        var firstImg = tmpDiv.querySelector("img");
        if(firstImg) imgUrl = firstImg.src || firstImg.getAttribute("src") || "";
      }
      // 이미지 없으면 미디어 썸네일 시도
      if(!imgUrl && e.media$thumbnail){
        imgUrl = e.media$thumbnail.url || "";
      }

      // 요약 추출
      var desc = "";
      if(e.content && e.content.$t){
        var tmpDiv2 = document.createElement("div");
        tmpDiv2.innerHTML = e.content.$t;
        var badTags = tmpDiv2.querySelectorAll("style, script, noscript, img");
        for(var k=0;k<badTags.length;k++) badTags[k].remove();
        desc = (tmpDiv2.textContent || "").replace(/\s{2,}/g," ").trim().substring(0,100) + "...";
      }

      var imgHTML = imgUrl 
        ? '<div class="onecut-img"><img src="' + imgUrl + '" alt="' + title + '"/></div>'
        : '<div class="onecut-img" style="background:#e8e8e4;display:flex;align-items:center;justify-content:center;color:#bbb;font-size:11px;letter-spacing:1px;">IMAGE</div>';

      html += '<div class="onecut-card">' +
        imgHTML +
        '<div class="onecut-content">' +
        '<div class="onecut-title"><a href="' + link + '">' + title + '</a></div>' +
        '<div class="onecut-meta">' + date + ' · 22B Labs</div>' +
        '<div class="onecut-desc">' + desc + '</div>' +
        '</div></div>';
    }

    grid.innerHTML = html;
    section.style.display = "block";
  };

  // "한컷" 라벨로 필터링해서 가져오기
  var ocScript = document.createElement("script");
  ocScript.src = blogUrl + "/feeds/posts/default/-/%ED%95%9C%EC%BB%B7?alt=json-in-script&max-results=4&callback=renderOnecut";
  document.body.appendChild(ocScript);

})();
//

b:includable.script:
//
(function(){
  var bodies = document.querySelectorAll('.post-body');
  for(var i=0;i<bodies.length;i++){
    var h2s = bodies[i].querySelectorAll('h2');
    if(h2s.length >= 2){
      var adDiv = document.createElement('div');
      adDiv.className = 'ad-slot';
      adDiv.id = 'ad-post-mid';
      adDiv.style.margin = '28px 0';
      adDiv.textContent = 'ADVERTISEMENT';
      h2s[1].parentNode.insertBefore(adDiv, h2s[1]);
    }
  }
})();
