b:if.script:
//
(function(){
  var blogUrl = "https://www.the4thpath.com";

  // ── 이전/다음 글 렌더링 ──
  var prevNext = document.getElementById("ps-prevnext");
  var pagerLinks = document.querySelectorAll(".blog-pager a");
  if(pagerLinks.length > 0 && prevNext){
    var html = '<div class="ps-title">Navigation</div>';
    for(var i=0;i<pagerLinks.length;i++){
      var a = pagerLinks[i];
      var dir = a.textContent.indexOf("Newer") >= 0 ? "← 이전 글" : "다음 글 →";
      html += '<a class="ps-nav-item" href="' + a.href + '"><span class="dir">' + dir + '</span></a>';
    }
    prevNext.innerHTML = html;
  }

  // ── 연관 글 렌더링 (최신 글 중 현재 글 제외) ──
  window.renderRelated = function(data){
    var entries = data.feed.entry || [];
    var container = document.getElementById("ps-related");
    if(!container || entries.length === 0) return;

    var currentUrl = window.location.href;
    var html = "";
    var count = 0;

    for(var i=0; i<entries.length && count<6; i++){
      var e = entries[i];
      var link = "";
      for(var j=0;j<e.link.length;j++){
        if(e.link[j].rel==="alternate"){link=e.link[j].href;break;}
      }
      if(link === currentUrl) continue;

      var labels = [];
      if(e.category){
        for(var k=0;k<e.category.length;k++) labels.push(e.category[k].term);
      }
      // 한컷 제외
      if(labels.indexOf("한컷") >= 0) continue;

      var label = labels.length > 0 ? labels[0] : "";
      var title = e.title.$t;
      var date = "";
      if(e.published){
        var d = new Date(e.published.$t);
        date = d.getFullYear()+"."+ ("0"+(d.getMonth()+1)).slice(-2)+"."+ ("0"+d.getDate()).slice(-2);
      }

      html += '<a class="ps-nav-item" href="' + link + '" style="text-decoration:none;">' +
        '<div class="ps-nav-label">' + label + '</div>' +
        '<div class="ps-nav-title">' + title + '</div>' +
        '<div class="ps-nav-date">' + date + '</div></a>';
      count++;
    }
    container.innerHTML = html;
  };

  var s = document.createElement("script");
  s.src = blogUrl + "/feeds/posts/default?alt=json-in-script&max-results=15&callback=renderRelated";
  document.body.appendChild(s);
})();
//

body.script:
//
var allPostsData = [];
var allPostsLoaded = false;

function showAllPosts(e) {
  if(e) e.preventDefault();

  // 홈페이지 콘텐츠 숨기기
  var hp = document.querySelector('.hp');
  var postPage = document.querySelector('.post-page-grid');
  if(hp) hp.style.display = 'none';
  if(postPage) postPage.style.display = 'none';

  // 전체글 페이지 보이기
  var ap = document.getElementById('allposts-page');
  ap.style.display = 'block';

  // 데이터 로드 (최초 1회)
  if(!allPostsLoaded) loadAllPosts();
}

function hideAllPosts() {
  var ap = document.getElementById('allposts-page');
  if(ap) ap.style.display = 'none';
  var hp = document.querySelector('.hp');
  if(hp) hp.style.display = '';
}

function loadAllPosts() {
  var blogUrl = "https://www.the4thpath.com";

  function fetch(startIndex, callback) {
    var s = document.createElement('script');
    s.src = blogUrl + '/feeds/posts/default?alt=json-in-script&max-results=50&start-index=' + startIndex + '&callback=' + callback;
    document.body.appendChild(s);
  }

  window._allPostsBatch1 = function(data) {
    var entries = data.feed.entry || [];
    entries.forEach(function(e) {
      var link = '';
      for(var i=0;i<e.link.length;i++) {
        if(e.link[i].rel==='alternate'){link=e.link[i].href;break;}
      }
      var labels = [];
      if(e.category) {
        for(var j=0;j<e.category.length;j++) labels.push(e.category[j].term);
      }
      var date = '';
      if(e.published) {
        var d = new Date(e.published.$t);
        date = d.getFullYear()+'.'+ ('0'+(d.getMonth()+1)).slice(-2)+'.'+ ('0'+d.getDate()).slice(-2);
      }
      allPostsData.push({
        title: e.title.$t,
        url: link,
        labels: labels,
        date: date
      });
    });

    // 50개 이상이면 다음 배치 로드
    var total = parseInt(data.feed.openSearch$totalResults.$t) || 0;
    if(allPostsData.length < total && entries.length === 50) {
      fetch(allPostsData.length + 1, '_allPostsBatch2');
    } else {
      renderAllPosts('all');
      allPostsLoaded = true;
    }
  };

  window._allPostsBatch2 = function(data) {
    var entries = data.feed.entry || [];
    entries.forEach(function(e) {
      var link = '';
      for(var i=0;i<e.link.length;i++) {
        if(e.link[i].rel==='alternate'){link=e.link[i].href;break;}
      }
      var labels = [];
      if(e.category) {
        for(var j=0;j<e.category.length;j++) labels.push(e.category[j].term);
      }
      var date = '';
      if(e.published) {
        var d = new Date(e.published.$t);
        date = d.getFullYear()+'.'+ ('0'+(d.getMonth()+1)).slice(-2)+'.'+ ('0'+d.getDate()).slice(-2);
      }
      allPostsData.push({
        title: e.title.$t,
        url: link,
        labels: labels,
        date: date
      });
    });
    renderAllPosts('all');
    allPostsLoaded = true;
  };

  fetch(1, '_allPostsBatch1');
}

function renderAllPosts(filter) {
  var list = document.getElementById('allposts-list');
  var countEl = document.getElementById('allposts-count');
  var filtered = filter === 'all' 
    ? allPostsData 
    : allPostsData.filter(function(p){ return p.labels.indexOf(filter) >= 0; });

  countEl.textContent = filtered.length + ' articles';

  if(filtered.length === 0) {
    list.innerHTML = '<li style="padding:20px 0;color:#bbb;text-align:center;">No articles found.</li>';
    return;
  }

  var html = '';
  for(var i=0; i<filtered.length; i++) {
    var p = filtered[i];
    var label = p.labels.length > 0 ? p.labels[0] : '';
    html += '<li class="allposts-item">' +
      '<div class="allposts-item-left">' +
      '<div class="allposts-item-label">' + label + '</div>' +
      '<div class="allposts-item-title"><a href="' + p.url + '">' + p.title + '</a></div>' +
      '</div>' +
      '<div class="allposts-item-date">' + p.date + '</div>' +
      '</li>';
  }
  list.innerHTML = html;
}

function filterPosts(filter) {
  // 필터 버튼 active 상태 변경
  var btns = document.querySelectorAll('.allposts-filter');
  for(var i=0;i<btns.length;i++) btns[i].classList.remove('active');
  event.target.classList.add('active');
  renderAllPosts(filter);
}

// Home 링크 클릭 시 전체글 페이지 숨기기
document.addEventListener('DOMContentLoaded', function(){
  var homeLinks = document.querySelectorAll('.nav a[href="/"]');
  for(var i=0;i<homeLinks.length;i++){
    homeLinks[i].addEventListener('click', function(e){
      var ap = document.getElementById('allposts-page');
      if(ap && ap.style.display === 'block'){
        e.preventDefault();
        hideAllPosts();
      }
    });
  }
});
//
